        errorMessage = nil
        legacyResponse = "Fetching legacy data..."
        performRequest(url: legacyURL) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let data):
                    self?.legacyResponse = String(data: data, encoding: .utf8) ?? "Invalid legacy data"
                case .failure(let error):
                    self?.legacyResponse = "Legacy Error: \(error.localizedDescription)"
                    self?.errorMessage = error.localizedDescription
                }
            }
